  1260→        PyObject *obj, int max_dims,
  1261→        npy_intp out_shape[NPY_MAXDIMS],
  1262→        coercion_cache_obj **coercion_cache,
  1263→        PyArray_DTypeMeta *fixed_DType, PyArray_Descr *requested_descr,
  1264→        PyArray_Descr **out_descr, int copy, int *was_copied_by__array__)
  1265→{
