  1281→        if (fixed_DType != NULL) {
  1282→            assert(fixed_DType == NPY_DTYPE(requested_descr));
  1283→        }
  1284→        /* The output descriptor must be the input. */
  1285→        Py_INCREF(requested_descr);
  1286→        *out_descr = requested_descr;
  1287→        flags |= DESCRIPTOR_WAS_SET;
  1288→    }
  1289→
  1290→    /*
  1291→     * Call the recursive function, the setup for this may need expanding
  1292→     * to handle caching better.
  1293→     */
  1294→
  1295→    /* Legacy discovery flags */
  1296→    if (requested_descr != NULL) {
  1297→        if (requested_descr->type_num == NPY_STRING &&
  1298→                requested_descr->type == 'c') {
  1299→            /* Character dtype variation of string (should be deprecated...) */
  1300→            flags |= DISCOVER_STRINGS_AS_SEQUENCES;
  1301→        }
  1302→        else if (requested_descr->type_num == NPY_VOID &&
  1303→                    (((_PyArray_LegacyDescr *)requested_descr)->names
  1304→                     || ((_PyArray_LegacyDescr *)requested_descr)->subarray))  {
  1305→            /* Void is a chimera, in that it may or may not be structured... */
  1306→            flags |= DISCOVER_TUPLES_AS_ELEMENTS;
  1307→        }
  1308→    }
  1309→
  1310→    int ndim = PyArray_DiscoverDTypeAndShape_Recursive(
  1311→            obj, 0, max_dims, out_descr, out_shape, &coercion_cache,
  1312→            fixed_DType, &flags, copy);
  1313→    if (ndim < 0) {
  1314→        goto fail;
  1315→    }
  1316→
  1317→    if (was_copied_by__array__ != NULL && flags & COPY_WAS_CREATED_BY__ARRAY__) {
  1318→        *was_copied_by__array__ = 1;
